  { id: "p237", english: "What does this word mean?", hungarian: "Mit jelent ez a szó?", emoji: "🤔", literal: "Mit tesz ez a szó jelenteni?", categoryId: "tanulas" },
  { id: "p238", english: "Could you repeat that?", hungarian: "Megismételnéd?", emoji: "🔁", literal: "Tudnád te ismételni azt?", categoryId: "tanulas" },
  { id: "p239", english: "I need to improve my vocabulary.", hungarian: "Fejlesztenem kell a szókincsemet.", emoji: "📈", literal: "Én szükségem van javítani a szókincsemet.", categoryId: "tanulas" },
  { id: "p240", english: "English pronunciation is hard.", hungarian: "Az angol kiejtés nehéz.", emoji: "🗣️", literal: "Az angol kiejtés van kemény.", categoryId: "tanulas" }
